// Helper functions
export function getPageBySlug(slug: string): ContentPage | undefined {
  return pages.find((p) => p.slug === slug)
}

export function getPagesByCategory(category: ContentPage['category']): ContentPage[] {
  return pages.filter((p) => p.category === category)
}

export function getP0Pages(): ContentPage[] {
  return pages.filter((p) => p.priority === 'P0')
}
